 function discardItem(area:"hands"|"bag",index:number){const item=hero[area][index];if(!item)return;const cost=area==="bag"?1:0;if(hero.actions<cost)return ping("Tossing a carried item costs 1 action");commit(g=>{const h=g.heroes[g.active],discarded=h[area][index];if(!discarded)return g;h[area][index]=null;h.actions-=cost;log(g,`${h.name} discards ${discarded.name}${cost?" (1 AP)":""}.`);return g});setPicked(null);announce(`${item.name.toUpperCase()} DISCARDED`)}
 function giveItem(index:number,targetId:number){const item=hero.bag[index];if(!item)return;const target=game.heroes.find(h=>h.id===targetId);if(!target||(target.floor||0)!==floor||target.x!==hero.x||target.y!==hero.y)return ping("Survivors must share a zone and floor");if(hero.actions<1)return;commit(g=>{const from=g.heroes[g.active],to=g.heroes.find(h=>h.id===targetId);if(!to)return g;const source=from.bag[index],dest=to.bag.findIndex(v=>!v);if(!source)return g;if(dest<0){log(g,`${to.name}'s bag is full.`);return g}from.bag[index]=null;to.bag[dest]={...source};from.actions--;log(g,`${from.name} gives ${source.name} to ${to.name}.`);return g});announce(`${item.name.toUpperCase()} TRANSFERRED`)}
