 useEffect(()=>{if(new URLSearchParams(location.search).get("platform")!=="androidtv")return;const frame=requestAnimationFrame(()=>{const layer=document.querySelector<HTMLElement>('.missionbrief,.modal,.victory,.defeat,.sessionnotice'),target=layer?.querySelector<HTMLElement>('[data-tv-primary]')||layer?.querySelector<HTMLElement>('button:not(:disabled),a[href],input:not(:disabled),[tabindex="0"]')||document.querySelector<HTMLElement>('[data-tv-primary]:not(:disabled),.mode-grid button:not(:disabled),.mission-cards button:not(:disabled),.online-options button:not(:disabled)');target?.focus()});return()=>cancelAnimationFrame(frame)},[screen,briefing,inventory,confirmQuit,confirmEndTurn,about,sessionEnded,game.status]);

 useEffect(()=>{const onKey=(e:KeyboardEvent)=>{const tag=(e.target as HTMLElement)?.tagName;if(tag==="INPUT"||tag==="TEXTAREA"||tag==="SELECT")return;if(e.key==="Escape"){e.preventDefault();if(about)setAbout(false);else if(inventory){setInventory(false);setPicked(null)}else if(confirmEndTurn)setConfirmEndTurn(false);else if(confirmQuit)setConfirmQuit(false);else if(briefing){setBriefing(false);setScreen("setup")}else if(screen==="rules"||screen==="online")setScreen("menu");else if(screen==="setup"){setScreen(setupMode==="online"?"connect":"menu");if(roomId&&isHost)updateLobby("room")}else if(screen==="connect")terminateGame();else if(screen==="game")setConfirmQuit(true);return}if(screen!=="game"||briefing||inventory||confirmQuit||confirmEndTurn||game.status!=="playing")return;if(e.code==="Space"){e.preventDefault();if(hero.actions>0)setConfirmEndTurn(true);else endTurn()}else if(e.key==="1"){e.preventDefault();switchHands()}else if(e.key.toLowerCase()==="i"){e.preventDefault();setInventory(true)}else if(e.key.toLowerCase()==="m"){e.preventDefault();heal()}else if(e.key.toLowerCase()==="b"){e.preventDefault();openDoor()}else if(e.key.toLowerCase()==="s"){e.preventDefault();search()}};addEventListener("keydown",onKey);return()=>removeEventListener("keydown",onKey)},[screen,briefing,inventory,confirmQuit,confirmEndTurn,about,game.status,game.active,hero.actions,game,setupMode,roomId,isHost]);

